// Получаем все входные элементы
const allItems = $input.all();

// Берём первый (и, скорее всего, единственный) элемент
const rootItem = allItems[0]?.json;

// Проверяем структуру
if (!rootItem || !Array.isArray(rootItem.workers)) {
  throw new Error('Неверный формат: ожидается объект с полем "workers" (массив)');
}

// Фильтруем воркеры: idle и не worker-8080
const eligibleWorkers = rootItem.workers.filter(w => 
  w.status === 'idle' && 
  w.workerId !== 'worker-8080'
);

if (eligibleWorkers.length === 0) {
  throw new Error('Нет доступных воркеров, кроме worker-8080');
}

// Берём первый подходящий (или случайный — по желанию)
const selected = eligibleWorkers[0];

return {
  json: {
    workerId: selected.workerId,
    wsUrl: (selected.wsUrl || '').trim()
  }
};

